// Load RSS sources from config/rss-sources.yaml at runtime.
// In production the YAML is pre-baked into an env var RSS_SOURCES_JSON by a startup script.
// Fallback: use a minimal hardcoded list so the workflow boots without config.
const sourcesJson = $env.RSS_SOURCES_JSON || null;
let sources;
if (sourcesJson) {
  sources = JSON.parse(sourcesJson);
} else {
  sources = [
    { id: 'hackernews-best', name: 'Hacker News Best', url: 'https://hnrss.org/best', category: 'tech' },
    { id: 'anthropic-blog', name: 'Anthropic Blog', url: 'https://www.anthropic.com/rss.xml', category: 'ai' },
    { id: 'verge-ai', name: 'The Verge AI', url: 'https://www.theverge.com/rss/ai-artificial-intelligence/index.xml', category: 'ai' }
  ];
}
return sources.map(s => ({ json: s }));

// Attach source metadata to each item so the filter node can use it.
const sourceId = $('Load RSS Sources').item.json.id;
const sourceName = $('Load RSS Sources').item.json.name;
const category = $('Load RSS Sources').item.json.category;

const items = $input.all();
if (!items || items.length === 0) return [];

return items.map(item => ({
  json: {
    ...item.json,
    feed_id: sourceId,
    feed_name: sourceName,
    feed_category: category,
    fetched_at: new Date().toISOString()
  }
}));

// Keyword filter — mirrors config/keyword-filters.yaml logic.
// INCLUDE: item must score >= 1 on weighted include keyword list.
// EXCLUDE: item is dropped if any exclude keyword matches.
// TRUSTED: items from trusted_sources bypass keyword check.

const TRUSTED_SOURCES = ['anthropic-blog', 'linear-changelog'];
const MAX_ITEMS_PER_RUN = 20;

const INCLUDE = [
  { kw: 'claude', w: 3 }, { kw: 'anthropic', w: 3 },
  { kw: 'openai', w: 2 }, { kw: 'llm', w: 2 }, { kw: 'large language model', w: 2 },
  { kw: 'gpt', w: 2 }, { kw: 'gemini', w: 2 }, { kw: 'qwen', w: 2 }, { kw: 'mistral', w: 2 },
  { kw: 'agent', w: 2 }, { kw: 'agentic', w: 2 }, { kw: 'autonomous', w: 2 },
  { kw: 'mcp', w: 2 }, { kw: 'model context protocol', w: 3 },
  { kw: 'cursor', w: 1 }, { kw: 'github copilot', w: 1 }, { kw: 'developer tool', w: 1 },
  { kw: 'fastapi', w: 1 }, { kw: 'next.js', w: 1 }, { kw: 'vercel', w: 1 }, { kw: 'railway', w: 1 },
  { kw: 'saas', w: 1 }, { kw: 'bootstrapped', w: 1 }, { kw: 'mrr', w: 1 },
  { kw: 'disaster recovery', w: 2 }, { kw: 'restore', w: 1 }, { kw: 'emergency management', w: 2 }
];

const EXCLUDE = [
  'sports', 'recipe', 'fashion', 'celebrity', 'movie review',
  'real estate', 'crypto', 'nft', 'web3', 'lawsuit',
  'congressional', 'senate hearing'
];

function scoreItem(item) {
  const haystack = ((item.title || '') + ' ' + (item.contentSnippet || item.content || '')).toLowerCase();
  for (const ex of EXCLUDE) {
    if (haystack.includes(ex)) return -1;
  }
  if (TRUSTED_SOURCES.includes(item.feed_id)) return 999;
  let score = 0;
  for (const { kw, w } of INCLUDE) {
    if (haystack.includes(kw)) score += w;
  }
  return score;
}

const items = $input.all();
const scored = items
  .map(i => ({ ...i, _score: scoreItem(i.json) }))
  .filter(i => i._score >= 1)
  .sort((a, b) => b._score - a._score)
  .slice(0, MAX_ITEMS_PER_RUN);

return scored.map(i => ({ json: { ...i.json, relevance_score: i._score } }));

// Aggregate all filtered items into a single list for Google Docs append.
const all = $input.all().map(i => i.json);
return [{ json: { items: all, count: all.length, aggregated_at: new Date().toISOString() } }];

// Build a Google Docs batchUpdate append request.
// Appends a timestamped header + bulleted item list after the last character.
const doc = $('Get Google Doc').first().json;
const endIndex = doc.body.content.slice(-1)[0]?.endIndex - 1 || 1;
const items = $('Aggregate Items').first().json.items;
const now = new Date().toISOString().slice(0, 16).replace('T', ' ') + ' UTC';

const requests = [];

// Section header
requests.push({
  insertText: {
    location: { index: endIndex },
    text: `\n\n── ${now} (${items.length} items) ──\n`
  }
});

let insertAt = endIndex + `\n\n── ${now} (${items.length} items) ──\n`.length;

// One line per item
for (const item of items) {
  const line = `[${item.feed_name}] ${item.title || '(untitled)'} — ${item.link || item.url || ''}\n`;
  requests.push({ insertText: { location: { index: insertAt }, text: line } });
  insertAt += line.length;
}

return [{ json: { requests, doc_id: doc.documentId, doc_title: doc.title, items_added: items.length } }];

