// Parse Qwen response and validate structure.
const resp = $input.first().json;
const raw = resp.choices?.[0]?.message?.content?.trim();
if (!raw) throw new Error('Qwen returned empty content');

let brief;
try {
  brief = JSON.parse(raw);
} catch (e) {
  throw new Error(`Qwen output is not valid JSON: ${raw.slice(0, 200)}`);
}

// Basic schema validation
const required = ['date', 'headline', 'sections', 'action_items', 'risk_flags'];
for (const key of required) {
  if (!(key in brief)) throw new Error(`Brief missing key: ${key}`);
}
if (!Array.isArray(brief.sections) || brief.sections.length === 0) {
  throw new Error('Brief.sections must be a non-empty array');
}

return [{ json: { brief, valid: true, generated_at: new Date().toISOString() } }];

// Format the Telegram message from the validated brief.
const { brief } = $input.first().json;
const gdocUrl = $env.GDOC_BRIEF_URL || '';
const docLink = gdocUrl ? `\n📄 [Full brief](${gdocUrl})` : '';

let text = `*Pi-CEO Intelligence Brief — ${brief.date}*\n\n_${brief.headline}_`;

for (const section of brief.sections) {
  text += `\n\n*${section.title}*`;
  for (const item of (section.items || [])) {
    const link = item.url ? `[${item.source}](${item.url})` : item.source;
    text += `\n• ${item.summary} — ${link}`;
  }
}

if (brief.action_items?.length) {
  text += '\n\n*Actions*\n' + brief.action_items.map(a => `  • ${a}`).join('\n');
}
if (brief.risk_flags?.length) {
  text += '\n\n*Risk flags*\n' + brief.risk_flags.map(r => `  ⚠️ ${r}`).join('\n');
}
text += docLink;

return [{ json: { text, brief } }];

const resp = $input.first().json;
if (!resp.ok) {
  throw new Error(`Telegram send failed: ${JSON.stringify(resp)}`);
}
console.log('[rss-pipeline] Telegram message sent, message_id:', resp.result?.message_id);
return [{ json: { status: 'delivered', message_id: resp.result?.message_id, finished_at: new Date().toISOString() } }];

// No items passed the keyword filter — log and exit cleanly.
console.log('[rss-pipeline] No items passed keyword filter this run.');
return [{ json: { status: 'skipped', reason: 'no_items_after_filter', skipped_at: new Date().toISOString() } }];
